Create the `PasswordInput` component in `shared/ui` with eye/eye-off visibility toggle. Supports both controlled and uncontrolled modes. Also write component tests.

## Component Implementation

Create `apps/client/src/layers/shared/ui/password-input.tsx`:

```tsx
import * as React from 'react';
import { useState } from 'react';
import { Eye, EyeOff } from 'lucide-react';
import { Input, type InputProps } from './input';
import { Button } from './button';
import { cn } from '@/layers/shared/lib';

interface PasswordInputProps extends Omit<InputProps, 'type'> {
  /** Controlled visibility state. When provided, component is controlled. */
  showPassword?: boolean;
  /** Callback when visibility toggle is clicked (controlled mode). */
  onShowPasswordChange?: (show: boolean) => void;
  /** Initial visibility state for uncontrolled mode. Defaults to false. */
  visibleByDefault?: boolean;
}

/**
 * Password input with eye/eye-off visibility toggle.
 *
 * Supports both controlled (`showPassword` + `onShowPasswordChange`) and
 * uncontrolled (`visibleByDefault`) modes.
 */
function PasswordInput({
  className,
  showPassword: controlledShow,
  onShowPasswordChange,
  visibleByDefault = false,
  ...props
}: PasswordInputProps) {
  const [internalShow, setInternalShow] = useState(visibleByDefault);
  const isControlled = controlledShow !== undefined;
  const isVisible = isControlled ? controlledShow : internalShow;

  const toggleVisibility = () => {
    if (isControlled) {
      onShowPasswordChange?.(!controlledShow);
    } else {
      setInternalShow((prev) => !prev);
    }
  };

  return (
    <div className="relative">
      <Input
        type={isVisible ? 'text' : 'password'}
        className={cn('pr-10', className)}
        {...props}
      />
      <Button
        type="button"
        variant="ghost"
        size="sm"
        className="absolute right-0 top-0 h-full px-3"
        onClick={toggleVisibility}
        aria-label={isVisible ? 'Hide password' : 'Show password'}
      >
        {isVisible ? <EyeOff className="size-4" /> : <Eye className="size-4" />}
      </Button>
    </div>
  );
}

export { PasswordInput };
export type { PasswordInputProps };
```

**Design notes:**
- Sentinel behavior (clearing on focus, showing "Saved — enter a new one to replace") is a *consumer concern*, not a PasswordInput concern. The calling code passes `onFocus`, `placeholder`, and `value` props.
- PasswordInput just handles visibility toggling via `type="password"` / `type="text"`.

## Barrel Export

Add to `apps/client/src/layers/shared/ui/index.ts`:

```tsx
export { PasswordInput } from './password-input';
export type { PasswordInputProps } from './password-input';
```

## Tests

Create `apps/client/src/layers/shared/ui/__tests__/password-input.test.tsx`:

```tsx
/**
 * @vitest-environment jsdom
 */
import { describe, it, expect, vi } from 'vitest';
import { render, screen } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import '@testing-library/jest-dom';
import { PasswordInput } from '../password-input';

describe('PasswordInput', () => {
  it('renders as password type by default', () => {
    render(<PasswordInput placeholder="Enter password" />);
    expect(screen.getByPlaceholderText('Enter password')).toHaveAttribute('type', 'password');
  });

  it('toggles visibility on button click', async () => {
    const user = userEvent.setup();
    render(<PasswordInput placeholder="Secret" />);
    const input = screen.getByPlaceholderText('Secret');
    const toggle = screen.getByRole('button', { name: 'Show password' });

    expect(input).toHaveAttribute('type', 'password');
    await user.click(toggle);
    expect(input).toHaveAttribute('type', 'text');
    expect(screen.getByRole('button', { name: 'Hide password' })).toBeInTheDocument();
  });

  it('respects controlled showPassword prop', () => {
    const onChange = vi.fn();
    render(<PasswordInput showPassword={true} onShowPasswordChange={onChange} />);
    // When showPassword is true, input type should be 'text'
    const input = screen.getByRole('textbox');
    expect(input).toHaveAttribute('type', 'text');
  });

  it('calls onShowPasswordChange in controlled mode', async () => {
    const user = userEvent.setup();
    const onChange = vi.fn();
    render(<PasswordInput showPassword={false} onShowPasswordChange={onChange} />);
    await user.click(screen.getByRole('button', { name: 'Show password' }));
    expect(onChange).toHaveBeenCalledWith(true);
  });

  it('starts visible when visibleByDefault is true', () => {
    render(<PasswordInput visibleByDefault placeholder="Token" />);
    expect(screen.getByPlaceholderText('Token')).toHaveAttribute('type', 'text');
  });

  it('forwards standard input props', () => {
    render(<PasswordInput placeholder="Secret" id="my-pw" disabled />);
    const input = screen.getByPlaceholderText('Secret');
    expect(input).toHaveAttribute('id', 'my-pw');
    expect(input).toBeDisabled();
  });
});
```

Run the tests: `pnpm vitest run apps/client/src/layers/shared/ui/__tests__/password-input.test.tsx`

## Acceptance Criteria

- `password-input.tsx` exists at `apps/client/src/layers/shared/ui/password-input.tsx`
- Component is exported from the shared UI barrel
- All 6 tests pass
- Component supports both controlled (`showPassword` + `onShowPasswordChange`) and uncontrolled (`visibleByDefault`) modes
- `pnpm typecheck --filter=@dorkos/client` passes

